/**
 * Calls OddsJam API using ODDSJAM_API_KEY env var to find live arbitrage opportunities. Falls back gracefully if the key is not configured.

 * @summary Get live arbitrage opportunities
 */
export const getGetArbitrageOpportunitiesUrl = (
  params?: GetArbitrageOpportunitiesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/arbitrage/opportunities?${stringifiedParams}`
    : `/api/arbitrage/opportunities`;
};

export const getArbitrageOpportunities = async (
  params?: GetArbitrageOpportunitiesParams,
  options?: RequestInit,
): Promise<ArbitrageResponse> => {
  return customFetch<ArbitrageResponse>(
    getGetArbitrageOpportunitiesUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

